(800021,2,'Linux - Linux创建自建服务','在init.d下创建服务 tech-doc内容如下: 原文链接：https://pdai.tech/md/devops/linux/linux-service.html','# Linux - Linux创建自建服务\n\n> 以打包自己开发的Java应用到Linux服务器，作为一个服务启动，并开启自启。 @pdai\n\n- Linux - Linux创建自建服务文件准备创建启动文件制作服务赋予权限开机自启查看端口查看防火墙\n\n## 文件准备\n\n```\n[root@docker opt]# tree -a\n.\n└── tech_doc\n    ├── bin\n    │   ├── logs\n    │   │   └── service.2018-10-31.log\n    │   └── tech_arch-0.0.1-RELEASE.jar\n    └── tech_doc\n```\n\n## 创建启动文件\n\ntech_doc\n\n```\n[root@docker opt]# cat tech_doc/tech_doc\n#!/bin/sh\n\n#------------------------------------------------\n# function: services start\n# author: pdai\n# home: /opt/tech_doc/bin\n# log: /var/log/tech_doc/process\n#------------------------------------------------\n\nHOME=/opt/tech_doc/bin\nLOGHOME=/var/log/tech_doc/process\n\nfunction serviceLoad()\n{\n  b=\'\'\n  i=0\n  while [ $i -le  100 ]\n  do\n      printf "$1:[%-50s]%d%%\\r" $b $i\n      sleep 0.3\n      i=`expr 2 + $i`\n      b=#$b\n  done\n  echo\n}\n\nfunction svcStart()\n{\n  echo "Starting $2 ..."\n  cd $1\n  PID=$(ps -ef | grep "$4" | grep -v grep | awk \'{print $2}\')\n  if [ -z "$PID" ]; then\n          nohup java -jar $3  > $5 2> $6 &\n    serviceLoad $SERVICE_NAME\n          echo "$2 started ..."\n  else\n          echo "$2 is already running ..."\n  fi\n}\n\nfunction svcStop()\n{\n  PID=$(ps -ef | grep "$1" | grep -v grep | awk \'{print $2}\')\n  if [ -z "$PID" ]; then\n          echo "$2 already stopped ..."\n  else\n    kill $PID\n        echo "$2 is stoping ..."\n  fi\n}\n\nfunction do_start()\n{\n  for FILE in `ls $HOME | grep jar`\n  do\n    FILE_NAME=$FILE\n    SERVICE_JAR_PACKAGE_PATH=$HOME/$FILE\n    SERVICE_NAME=${FILE_NAME%-[0-9]*}\n    SERVICE_LOG_PATH="$LOGHOME/$SERVICE_NAME.log"\n    SERVICE_ERR_LOG_PATH="$LOGHOME/$SERVICE_NAME.err"\n\n    svcStart $HOME $SERVICE_NAME $SERVICE_JAR_PACKAGE_PATH $FILE_NAME $SERVICE_LOG_PATH $SERVICE_ERR_LOG_PATH\n  done\n}\n\nfunction do_stop()\n{\n    for FILE in `ls $HOME | grep jar`\n  do\n    FILE_NAME=$FILE\n    SERVICE_NAME=${FILE_NAME%-[0-9]*}\n    SERVICE_PID_PATH="/tmp/$SERVICE_NAME.pid"\n\n    svcStop $FILE_NAME $SERVICE_NAME\n    sleep 1\n  done\n}\n\nfunction do_check()\n{\n    for FILE in `ls $HOME | grep jar`\n  do\n    FILE_NAME=$FILE\n    SERVICE_NAME=${FILE_NAME%-[0-9]*}\n    PID=$(ps -ef | grep $FILE_NAME | grep -v grep | awk \'{print $2}\')\n  if [ -z "$PID" ]; then\n          echo "$SERVICE_NAME $PID is not running ..."\n  else\n        echo "$SERVICE_NAME $PID is running ..."\n  fi\n\n    sleep 1\n  done\n}\n\ncase "$1" in\n    start)\n\n        do_start\n        echo start successful\n\n    ;;\n    stop)\n\n        do_stop\n        echo stop successful\n\n    ;;\n    restart)\n\n        do_stop\n              sleep 2\n        do_start\n        echo restart successful\n\n    ;;\n    status)\n\n        do_check\n\n    ;;\n    *)\n    echo "Usage: {start|stop|restart|status}" >&2\n    exit 3\n    ;;\nesac\nexit 0\n```\n\n## 制作服务\n\n在init.d下创建服务\n\n```\n[root@docker init.d]# tree -a\n.\n├── functions\n├── netconsole\n├── network\n├── README\n└── tech-doc\n```\n\ntech-doc内容如下:\n\n```\n[root@docker opt]# cd /etc/init.d\n[root@docker init.d]# ls\nfunctions  netconsole  network  README  tech-doc\n[root@docker init.d]# tree -a\n.\n├── functions\n├── netconsole\n├── network\n├── README\n└── tech-doc\n\n0 directories, 5 files\n[root@docker init.d]# ^C\n[root@docker init.d]# cat tech-doc\n#!/bin/sh\n#\n# /etc/init.d/tech-doc\n# chkconfig: 2345 60 20\n# description: ms.\n# processname: tech-doc\n\nSCRIPT_HOME=/opt/tech_doc\n\ncase $1 in\n    start)\n        sh $SCRIPT_HOME/tech_doc start\n    ;;\n    stop)\n        sh $SCRIPT_HOME/tech_doc stop\n    ;;\n    restart)\n        sh $SCRIPT_HOME/tech_doc stop\n        sh $SCRIPT_HOME/tech_doc start\n    ;;\n    status)\n        sh $SCRIPT_HOME/tech_doc status\n    ;;\n    *)\n    echo "Usage: {start|stop|restart|status}" >&2\n    exit 3\n    ;;\nesac\nexit 0\n```\n\n## 赋予权限\n\n```\nchmod 777 /etc/init.d/tech-doc\n```\n\n## 开机自启\n\n```\nchkconfig --list\nchkconfig tech-doc on\n```\n\n## 查看端口\n\n```\nnetstat -nltp\n```\n\n## 查看防火墙\n\n```\nsystemctl status firewalld\n```\n\n---\n\n原文链接：https://pdai.tech/md/devops/linux/linux-service.html','https://images.unsplash.com/photo-1602576666092-bf6447a729fc?w=800','Linux',NULL,0,NULL,'pdai-devops-linux-linux-service','Linux - Linux创建自建服务 - 技术博客','在init.d下创建服务 tech-doc内容如下: 原文链接：https://pdai.tech/md/devops/linux/linux-service.html',0,'PUBLISHED',843,43,63,1,'2025-08-03 00:00:00','2025-08-03 00:00:00','2026-05-08 23:54:10',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
