START TRANSACTION;






































UPDATE `blog_article_tag` SET `deleted_at`='2026-05-08 23:54:10',`updated_at`='2026-05-08 23:54:10' WHERE `article_id` IN (800000, 800001, 800002, 800003, 800004, 800005, 800006, 800007, 800008, 800009, 800010, 800011, 800012, 800013, 800014, 800015, 800016, 800017, 800018, 800019, 800020, 800021, 800022, 800023, 800024, 800025, 800026, 800027, 800028, 800029, 800030, 800031, 800032);


UPDATE `blog_column_article` SET `deleted_at`='2026-05-08 23:54:10',`updated_at`='2026-05-08 23:54:10' WHERE `column_id`=9200008;


UPDATE `blog_topic_article` SET `deleted_at`='2026-05-08 23:54:10',`updated_at`='2026-05-08 23:54:10' WHERE `topic_id` IN (9308001, 9308002, 9308003, 9308004);


UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL) WHERE t.`name` IN ('Docker', 'IO', 'Linux', '容器化 - Docker', '工具与运维', '工具清单', '开发工具详解');

UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE c.`id` IN (9200008);

UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE t.`id` IN (9308001, 9308002, 9308003, 9308004);

COMMIT;
